Perfect. Here's the refined canonical task brief schema, designed to be the single artifact that flows through every stage of the workflow.

---

## 📋 Canonical Task Brief — Schema v1.0
**Finalized:** 2026-02-23 21:27 SAST

```json
{
  "task_id": "string",
  // Format: {agent}_{YYYYMMDD}_{HHMM} e.g. "worker_20260223_2127"

  "created_at": "ISO8601 timestamp (SAST)",

  "source": {
    "type": "human | scheduled | agent",
    "origin": "alex | cron:{job_name} | {agent_name}",
    "session_ref": "string | null"
    // e.g. "heartbeat_20260223_2032" if spawned from a heartbeat
  },

  "intent": {
    "summary": "string",         // 1-sentence plain language
    "raw_input": "string | null" // Alex's original words if source=human
  },

  "risk": {
    "level": "low | medium | high",
    "flags": ["external_visibility", "irreversible", "data_sensitive"],
    // empty array if low risk
    "trustalign_required": "boolean",
    "trustalign_status": "not_required | pending | approved | blocked"
  },

  "assignment": {
    "primary_agent": "engage-x | contentway | trustalign | worker",
    "support_agents": ["string"],  // e.g. trustalign reviewing async
    "requires_human_confirmation": "boolean"
    // true for all browser automation tasks
  },

  "context_block": {
    "global": {},     // company voice, active campaign, current goals
    "agent_scoped": {},  // recent activity from assigned agent
    "task_scoped": {}    // ephemeral data specific to this task
  },

  "success_criteria": [
    "string"  // measurable, specific outcomes
    // e.g. "Blog post draft ≥600 words published to Notion by EOD"
    // e.g. "Twitter thread scheduled for 09:00 SAST 2026-02-24"
  ],

  "constraints": {
    "deadline": "ISO8601 | null",
    "budget_tokens": "integer | null",
    "confirmation_timeout_mins": 15
    // applies when requires_human_confirmation=true
  },

  "output": {
    "status": "pending | in_progress | awaiting_confirmation | completed | failed | parked",
    "result_summary": "string | null",
    "artifacts": [],         // links, file refs, post IDs
    "context_updates": [],   // written back to Echo context store
    "heartbeat_trigger": "boolean"
  }
}
```

### Example: Browser Automation Task (Post-Incident Design)

```json
{
  "task_id": "worker_20260223_2130",
  "source": {"type": "human", "origin": "alex", "session_ref": null},
  "intent": {"summary": "Log into CodexAI dashboard and screenshot active user count"},
  "risk": {"level": "medium", "flags": ["irreversible"], "trustalign_required": false, "trustalign_status": "not_required"},
  "assignment": {"primary_agent": "worker", "support_agents": [], "requires_human_confirmation": true},
  "success_criteria": ["Screenshot saved to /reports/codexai_users_20260223.png", "User count logged to context store"],
  "output": {"status": "awaiting_confirmation", "heartbeat_trigger": false}
}
```

---

This schema is fully traceable — `source.session_ref` links every task back to the session that spawned it, which closes the loop on our `discussed_in` tracking. Ready to approve and move to implementation guidance?
